    manual = f.read()

# Load data
payments = pd.read_csv('data/payments.csv')
with open('data/merchant_data.json','r') as f:
    merchants = pd.DataFrame(json.load(f))
with open('data/fees.json','r') as f:
    fees = json.load(f)

# Identify merchant row/columns
m = merchants.copy()
merchant_col = next((c for c in m.columns if 'merchant' in c.lower() and m[c].astype(str).eq('Belles_cookbook_store').any()), None)
if merchant_col is None:
    for c in m.columns:
        if m[c].astype(str).str.contains('Belles_cookbook_store', na=False).any():
            merchant_col = c
            break
row = m[m[merchant_col].astype(str)=='Belles_cookbook_store'].iloc[0]

# likely merchant id column
merchant_id_cols = [c for c in m.columns if c != merchant_col and ('id' in c.lower() or 'mid' in c.lower())]
merchant_id = None
for c in merchant_id_cols:
    val = row[c]
    if c in payments.columns and (payments[c].astype(str)==str(val)).any():
        merchant_id = (c, val)
        break

# filter January + merchant
date_col = next(c for c in payments.columns if 'date' in c.lower() or 'time' in c.lower())
p = payments.copy()
p[date_col] = pd.to_datetime(p[date_col], errors='coerce')
p = p[(p[date_col].dt.month==1)]

if merchant_id:
    c,val = merchant_id
    p = p[p[c].astype(str)==str(val)]
else:
    # fallback by merchant name column if present
    name_cols = [c for c in payments.columns if 'merchant' in c.lower() or 'store' in c.lower()]
    matched = False
    for c in name_cols:
        if p[c].astype(str).eq('Belles_cookbook_store').any():
            p = p[p[c].astype(str)=='Belles_cookbook_store']; matched=True; break
    if not matched:
        raise SystemExit("merchant not found")

# determine fraud column per manual likely boolean/label
fraud_cols = [c for c in p.columns if 'fraud' in c.lower()]
if not fraud_cols:
    fraud_cols = [c for c in p.columns if 'chargeback' in c.lower()]
fraud_col = fraud_cols[0]
vals = set(map(str, p[fraud_col].dropna().unique()))
if any(v.lower() in {'true','1','yes','fraud','fraudulent'} for v in vals):
    fraud_mask = p[fraud_col].astype(str).str.lower().isin(['true','1','yes','fraud','fraudulent'])
else:
    # assume 1 indicates fraud if numeric
    fraud_mask = pd.to_numeric(p[fraud_col], errors='coerce').fillna(0).astype(int)==1
p = p[fraud_mask].copy()

# infer needed columns
scheme_col = next(c for c in p.columns if 'scheme' in c.lower() or 'network' in c.lower() or 'brand' in c.lower())
aci_col = next(c for c in p.columns if c.lower()=='aci' or 'authorization characteristics indicator' in c.lower() or re.search(r'\baci\b', c.lower()))
amount_col = next(c for c in p.columns if 'amount' in c.lower() and 'fee' not in c.lower())
currency_col = next((c for c in p.columns if 'currency' in c.lower()), None)

# Build fee lookup recursively from json
def flatten_fee_entries(obj, path=None):
    path = path or []
    out = []
    if isinstance(obj, dict):
        # leaf if contains numeric-ish values or fee descriptors
        if any(isinstance(v,(int,float)) for v in obj.values()):
            out.append((path, obj))
        else:
            for k,v in obj.items():
                out.extend(flatten_fee_entries(v, path+[str(k)]))
    elif isinstance(obj, list):
        for i,v in enumerate(obj):
            out.extend(flatten_fee_entries(v, path+[str(i)]))
    return out

entries = flatten_fee_entries(fees)

def find_fee(scheme, aci, amount):
    s = str(scheme).lower()
    a = str(aci)
    candidates = []
    for path, leaf in entries:
        pstr = ' '.join(path).lower()
        if s in pstr and a.lower() in pstr:
            fixed = None; pct = None
            for k,v in leaf.items():
                lk = str(k).lower()
                if isinstance(v,(int,float)):
                    if '%' in lk or 'rate' in lk or 'percent' in lk or 'bps' in lk:
                        pct = float(v)
                    elif 'fixed' in lk or 'flat' in lk:
                        fixed = float(v)
            if fixed is None and pct is None:
                nums = [float(v) for v in leaf.values() if isinstance(v,(int,float))]
                if len(nums)==1:
                    fixed = nums[0]
                elif len(nums)>=2:
                    fixed,pct = nums[0],nums[1]
            if pct is not None and pct > 1:
                pct = pct/100.0
            fee = (fixed or 0.0) + amount*(pct or 0.0)
            candidates.append(fee)
    return min(candidates) if candidates else None

