vol = len(m_all)

def parse_num(s):
    s = s.replace('%','').strip()
    if s.endswith('k'): return float(s[:-1])*1000
    if s.endswith('m'): return float(s[:-1])*1000000
    return float(s)

def match(fee, row, aci):
    cs = row['card_scheme']
    is_credit = row['is_credit']
    intracountry = (row['issuing_country'] == row['acquirer_country'])
    if fee['card_scheme'] != cs: return False
    if fee['account_type'] and account_type not in fee['account_type']: return False
    if fee['merchant_category_code'] and mcc not in fee['merchant_category_code']: return False
    if fee['is_credit'] is not None and fee['is_credit'] != is_credit: return False
    if fee['aci'] and aci not in fee['aci']: return False
    if fee['intracountry'] is not None:
        if bool(fee['intracountry']) != intracountry: return False
    if fee['capture_delay'] is not None:
        cd = fee['capture_delay']
        if cd == 'immediate':
            if capture_delay != '0': return False
        elif cd == 'manual':
            if capture_delay != 'manual': return False
        elif cd.startswith('>'):
            if capture_delay=='manual' or int(capture_delay) <= int(cd[1:]): return False
        elif cd.startswith('<'):
            if capture_delay=='manual' or int(capture_delay) >= int(cd[1:]): return False
        elif '-' in cd:
            lo,hi=cd.split('-')
            if capture_delay=='manual' or not(int(lo)<=int(capture_delay)<=int(hi)): return False
    if fee['monthly_fraud_level'] is not None:
        mfl = fee['monthly_fraud_level']
        if mfl.startswith('>'):
            if fraud_rate <= parse_num(mfl[1:]): return False
        elif mfl.startswith('<'):
            if fraud_rate >= parse_num(mfl[1:]): return False
        elif '-' in mfl:
            lo,hi = mfl.replace('%','').split('-')
            if not(parse_num(lo)<=fraud_rate<=parse_num(hi)): return False
    if fee['monthly_volume'] is not None:
        mv = fee['monthly_volume']
        if mv.startswith('>'):
            if vol <= parse_num(mv[1:]): return False
        elif mv.startswith('<'):
            if vol >= parse_num(mv[1:]): return False
        elif '-' in mv:
            lo,hi = mv.split('-')
            if not(parse_num(lo)<=vol<=parse_num(hi)): return False
    return True

m = df[(df['merchant']=='Belles_cookbook_store') & (df['day_of_year']<=31) & (df['has_fraudulent_dispute']==True)].copy()

