import json, pandas as pd
fees = json.load(open('data/fees.json'))
payments = pd.read_csv('data/payments.csv')

# Filter Belles cookbook March 2023 (day_of_year 60-90 approx for March)
import datetime
p = payments[payments['merchant']=='Belles_cookbook_store'].copy()
p = p[p['year']==2023]
# March 2023: days 60 to 90 (2023 not leap; Jan=31, Feb=28, so March = day 60-90)
p = p[(p['day_of_year']>=60) & (p['day_of_year']<=90)]
print('Rows:', len(p))
print('Total volume:', p['eur_amount'].sum())
print('Fraud volume:', p[p['has_fraudulent_dispute']==True]['eur_amount'].sum())
print('Fraud rate:', p[p['has_fraudulent_dispute']==True]['eur_amount'].sum()/p['eur_amount'].sum())
print('Schemes:', p['card_scheme'].unique())
print('ACIs:', p['aci'].unique())
print('is_credit:', p['is_credit'].unique())

# Merchant properties
merchant = {'merchant': 'Belles_cookbook_store', 'capture_delay': '1', 'acquirer': ['lehman_brothers'], 'merchant_category_code': 5942, 'account_type': 'R'}
# capture_delay '1' means 1 day => '<3'

# Now compute applicable fees: rules that could apply to this merchant given account_type, mcc, capture_delay, monthly_volume, monthly_fraud_level
# Applicable = rule characteristics compatible; we consider all txn variants (is_credit, aci, intracountry)

total_vol = p['eur_amount'].sum()
fraud_rate = p[p['has_fraudulent_dispute']==True]['eur_amount'].sum()/total_vol
print(f'volume={total_vol}, fraud_rate={fraud_rate}')

def match_volume(rule_val, val):
    if rule_val is None: return True
    # parse ranges like '100k-1m', '<100k', '>5m'
    def parse(s):
        s=s.replace('k','e3').replace('m','e6')
        return float(s)
    if '-' in rule_val:
        lo,hi = rule_val.split('-')
        return parse(lo) <= val < parse(hi)
    if rule_val.startswith('<'):
        return val < parse(rule_val[1:])
    if rule_val.startswith('>'):
        return val > parse(rule_val[1:])
    return False

def match_fraud(rule_val, val):
    if rule_val is None: return True
    pct = val*100
    if '-' in rule_val:
        lo,hi = rule_val.replace('%','').split('-')
        return float(lo) <= pct < float(hi)
    if rule_val.startswith('<'):
        return pct < float(rule_val[1:].replace('%',''))
    if rule_val.startswith('>'):
        return pct > float(rule_val[1:].replace('%',''))
    return False

def match_capture(rule_val, days):
    if rule_val is None: return True
    if rule_val=='immediate': return days==0
    if rule_val=='manual': return False
    if rule_val=='<3': return days<3
    if rule_val=='>5': return days>5
    if rule_val=='3-5': return 3<=days<=5
    return False

applicable = []
for f in fees:
    # account_type
    if f.get('account_type') and len(f['account_type'])>0 and merchant['account_type'] not in f['account_type']:
        continue
    # mcc
    if f.get('merchant_category_code') and len(f['merchant_category_code'])>0 and merchant['merchant_category_code'] not in f['merchant_category_code']:
        continue
    # capture_delay
    if not match_capture(f.get('capture_delay'), int(merchant['capture_delay'])):
        continue
    # monthly volume
    if not match_volume(f.get('monthly_volume'), total_vol):
        continue
    # monthly fraud
    if not match_fraud(f.get('monthly_fraud_level'), fraud_rate):
        continue
    applicable.append(f['ID'])

print('Applicable IDs:', applicable)
print('Count:', len(applicable))
EOF"}

